//! `.gnarly` support for the Rust polyglot and gnexec surfaces.
//!
//! Gnot owns the syntax parser/normalizer. This module lowers the normalized
//! GG source into the same `PolyglotScanResult` / orchestration structures
//! emitted by language extractors so Monster/gnexec can consume it directly.

use std::collections::{BTreeMap, BTreeSet};
use std::path::Path;

use anyhow::Result;
use serde_json::{json, Value};

use crate::cfg::{FunctionSignature, SemanticContract};
use crate::diagnostics::{analyze_topology, compute_ghost_mass_ledger, filter_suppressed};
use crate::gg_compiler::{GgEdge, GgEdgeType, GgNode, GgTopology, GgTopologyMetadata};
use crate::gg_parser::{self, GgProgram};
use crate::serialization::{
    build_execution_manifest, PolyglotError, PolyglotExecutionManifest, PolyglotFunctionResult,
    PolyglotOrchestrationResult, PolyglotScanResult,
};
use crate::source_map::SourceMap;

pub fn is_gnarly_path(file_path: &str) -> bool {
    file_path.to_ascii_lowercase().ends_with(".gnarly")
}

pub fn is_gg_path(file_path: &str) -> bool {
    file_path.to_ascii_lowercase().ends_with(".gg")
}

pub fn normalize_gnarly_to_gg(source: &str, file_path: &str) -> String {
    gnot::parse_gnarly(source, file_path).gg_source
}

pub fn parse_and_extract_gg(source: &str, file_path: &str) -> Result<PolyglotScanResult> {
    compile_gg(source, file_path, GnarlyCompileMode::Analysis).map(|result| result.scan_result)
}

pub fn parse_and_extract_gg_orchestration(
    source: &str,
    file_path: &str,
) -> Result<PolyglotOrchestrationResult> {
    compile_gg(source, file_path, GnarlyCompileMode::Orchestration)
}

pub fn parse_and_extract_gnarly(source: &str, file_path: &str) -> Result<PolyglotScanResult> {
    compile_gnarly(source, file_path, GnarlyCompileMode::Analysis).map(|result| result.scan_result)
}

pub fn parse_and_extract_gnarly_orchestration(
    source: &str,
    file_path: &str,
) -> Result<PolyglotOrchestrationResult> {
    compile_gnarly(source, file_path, GnarlyCompileMode::Orchestration)
}

fn compile_gg(
    source: &str,
    file_path: &str,
    mode: GnarlyCompileMode,
) -> Result<PolyglotOrchestrationResult> {
    let program = gg_parser::parse_gg(source);
    let known_callees = BTreeSet::new();
    let function_name = gg_entry_function_name(&program).unwrap_or_else(|| file_stem(file_path));
    let main_topology = topology_from_program(
        &program,
        file_path,
        &function_name,
        None,
        &known_callees,
        mode,
    );

    let mut suppression_sources = std::collections::HashMap::new();
    suppression_sources.insert(file_path.to_string(), source.to_string());
    let diagnostics = filter_suppressed(analyze_topology(&main_topology), &suppression_sources);
    let ghost_mass_ledger = compute_ghost_mass_ledger(&main_topology);
    let manifest = build_execution_manifest(&main_topology);

    Ok(PolyglotOrchestrationResult {
        scan_result: PolyglotScanResult {
            file_path: file_path.to_string(),
            language: "gg".to_string(),
            structured_declarations: Vec::new(),
            proof_declarations: Vec::new(),
            topologies: vec![PolyglotFunctionResult {
                function_name: function_name.clone(),
                gg_source: main_topology.to_gg_source(),
                topology: main_topology,
                diagnostics,
                ghost_mass_ledger,
                signature: FunctionSignature::default(),
                semantic_contract: SemanticContract::default(),
            }],
            errors: Vec::new(),
        },
        manifest: PolyglotExecutionManifest {
            language: "gg".to_string(),
            file_path: file_path.to_string(),
            entry_function: function_name,
            node_execution_plans: manifest.node_execution_plans,
        },
    })
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum GnarlyCompileMode {
    Analysis,
    Orchestration,
}

fn compile_gnarly(
    source: &str,
    file_path: &str,
    mode: GnarlyCompileMode,
) -> Result<PolyglotOrchestrationResult> {
    let document = gnot::parse_gnarly(source, file_path);
    let program = gg_parser::parse_gg(&document.gg_source);
    let mut errors: Vec<PolyglotError> = document
        .diagnostics
        .iter()
        .map(|diagnostic| PolyglotError {
            message: diagnostic.message.clone(),
            line: Some(diagnostic.line),
            column: Some(diagnostic.column),
        })
        .collect();

    let mut extracted_topologies =
        extract_implementation_topologies(&document, file_path, mode, &mut errors);
    extracted_topologies.extend(extract_referenced_topologies(
        &document,
        &program,
        file_path,
        mode,
        &mut errors,
    ));

    let known_callees: BTreeSet<String> = extracted_topologies
        .iter()
        .map(|topology| topology.function_name.clone())
        .collect();

    let function_name = document
        .metadata
        .name
        .clone()
        .or_else(|| document.metadata.entry.clone())
        .unwrap_or_else(|| file_stem(file_path));
    let main_topology = topology_from_program(
        &program,
        file_path,
        &function_name,
        document.metadata.entry.as_deref(),
        &known_callees,
        mode,
    );

    let mut suppression_sources = std::collections::HashMap::new();
    suppression_sources.insert(file_path.to_string(), source.to_string());
    let diagnostics = filter_suppressed(analyze_topology(&main_topology), &suppression_sources);
    let ghost_mass_ledger = compute_ghost_mass_ledger(&main_topology);

    let mut topologies = Vec::with_capacity(extracted_topologies.len() + 1);
    topologies.push(PolyglotFunctionResult {
        function_name: function_name.clone(),
        gg_source: main_topology.to_gg_source(),
        topology: main_topology.clone(),
        diagnostics,
        ghost_mass_ledger,
        signature: FunctionSignature::default(),
        semantic_contract: SemanticContract::default(),
    });
    topologies.extend(extracted_topologies);

    let mut all_plans = Vec::new();
    for topology in &topologies {
        let manifest = build_execution_manifest(&topology.topology);
        all_plans.extend(manifest.node_execution_plans);
    }

    Ok(PolyglotOrchestrationResult {
        scan_result: PolyglotScanResult {
            file_path: file_path.to_string(),
            language: "gnarly".to_string(),
            structured_declarations: Vec::new(),
            proof_declarations: Vec::new(),
            topologies,
            errors,
        },
        manifest: PolyglotExecutionManifest {
            language: "gnarly".to_string(),
            file_path: file_path.to_string(),
            entry_function: function_name,
            node_execution_plans: all_plans,
        },
    })
}

fn extract_implementation_topologies(
    document: &gnot::GnarlyDocument,
    file_path: &str,
    mode: GnarlyCompileMode,
    errors: &mut Vec<PolyglotError>,
) -> Vec<PolyglotFunctionResult> {
    let mut topologies = Vec::new();
    for block in &document.implementations {
        let synthetic_path = implementation_file_path(file_path, block);
        match extract_source_topologies(&block.source_text, &synthetic_path, mode) {
            Ok(mut scan) => topologies.append(&mut scan.topologies),
            Err(error) => errors.push(PolyglotError {
                message: format!(
                    "implementation {} in {} could not be extracted: {error:#}",
                    block.node_id, block.language
                ),
                line: Some(block.start_line),
                column: Some(1),
            }),
        }
    }
    topologies
}

fn extract_referenced_topologies(
    document: &gnot::GnarlyDocument,
    program: &GgProgram,
    file_path: &str,
    mode: GnarlyCompileMode,
    errors: &mut Vec<PolyglotError>,
) -> Vec<PolyglotFunctionResult> {
    let mut topologies = Vec::new();
    let mut seen = BTreeSet::new();

    for node in program.nodes.values() {
        let Some(raw_file) = node.properties.get("file") else {
            continue;
        };
        if !seen.insert(raw_file.clone()) {
            continue;
        }
        let resolved = match gnot::resolve_gnarly_import_path(document, file_path, raw_file) {
            Ok(resolved) => resolved,
            Err(error) => {
                errors.push(PolyglotError {
                    message: error.to_string(),
                    line: None,
                    column: None,
                });
                continue;
            }
        };
        match std::fs::read_to_string(&resolved.absolute_path) {
            Ok(source) => match extract_source_topologies(
                &source,
                &resolved.absolute_path.to_string_lossy(),
                mode,
            ) {
                Ok(mut scan) => topologies.append(&mut scan.topologies),
                Err(error) => errors.push(PolyglotError {
                    message: format!(
                        "referenced file {} could not be extracted: {error:#}",
                        resolved.absolute_path.display()
                    ),
                    line: None,
                    column: None,
                }),
            },
            Err(error) => errors.push(PolyglotError {
                message: format!(
                    "referenced file {} could not be read: {error}",
                    resolved.absolute_path.display()
                ),
                line: None,
                column: None,
            }),
        }
    }

    topologies
}

fn extract_source_topologies(
    source: &str,
    file_path: &str,
    mode: GnarlyCompileMode,
) -> Result<PolyglotScanResult> {
    match mode {
        GnarlyCompileMode::Analysis => crate::parse_and_extract(source, file_path),
        GnarlyCompileMode::Orchestration => {
            crate::parse_and_extract_orchestration(source, file_path)
                .map(|result| result.scan_result)
        }
    }
}

fn topology_from_program(
    program: &GgProgram,
    file_path: &str,
    function_name: &str,
    explicit_entry: Option<&str>,
    known_callees: &BTreeSet<String>,
    mode: GnarlyCompileMode,
) -> GgTopology {
    let entry_target = explicit_entry
        .map(str::to_string)
        .or_else(|| first_edge_source(program))
        .or_else(|| program.nodes.keys().next().cloned())
        .unwrap_or_else(|| "main".to_string());
    let has_entry = program.nodes.values().any(|node| {
        split_labels(&node.labels)
            .iter()
            .any(|label| label == "Entry")
    });

    let mut nodes = Vec::new();
    if !has_entry {
        let mut props = BTreeMap::new();
        props.insert("name".to_string(), function_name.to_string());
        props.insert("gnarly_entry".to_string(), entry_target.clone());
        nodes.push(GgNode {
            id: "__gnarly_entry".to_string(),
            labels: vec!["Entry".to_string(), "PolyglotBridgeEntry".to_string()],
            properties: props,
            source_span: None,
        });
    }

    nodes.extend(program.nodes.values().map(|node| {
        let labels = split_labels(&node.labels);
        let mut properties = node.properties.clone();
        if matches!(mode, GnarlyCompileMode::Orchestration) {
            prepare_orchestration_properties(&mut properties, &labels, known_callees);
        }
        GgNode {
            id: node.id.clone(),
            labels,
            properties,
            source_span: None,
        }
    }));

    let mut edges = Vec::new();
    if !has_entry && program.nodes.contains_key(&entry_target) {
        edges.push(GgEdge {
            source_ids: vec!["__gnarly_entry".to_string()],
            target_ids: vec![entry_target],
            edge_type: GgEdgeType::Process,
            properties: BTreeMap::new(),
        });
    }
    edges.extend(program.edges.iter().map(|edge| GgEdge {
        source_ids: edge.source_ids.clone(),
        target_ids: edge.target_ids.clone(),
        edge_type: edge_type_from_str(&edge.edge_type),
        properties: edge.properties.clone(),
    }));

    GgTopology {
        nodes,
        edges,
        source_map: SourceMap::new(),
        metadata: GgTopologyMetadata {
            language: "gnarly".to_string(),
            file_path: file_path.to_string(),
            function_name: function_name.to_string(),
            extractor_version: env!("CARGO_PKG_VERSION").to_string(),
        },
    }
}

fn prepare_orchestration_properties(
    properties: &mut BTreeMap<String, String>,
    labels: &[String],
    known_callees: &BTreeSet<String>,
) {
    if properties.contains_key("expr") {
        return;
    }
    let is_call = labels
        .iter()
        .any(|label| label == "PolyglotBridgeCall" || label == "Statement");
    if !is_call {
        return;
    }

    let expr = match properties.get("callee") {
        Some(callee) if known_callees.contains(callee) => {
            json!({ "kind": "call", "callee": callee, "args": [] })
        }
        _ => json!({ "kind": "literal", "value": Value::Null }),
    };
    if let Ok(serialized) = serde_json::to_string(&expr) {
        properties.insert("expr".to_string(), serialized);
    }
}

fn split_labels(labels: &[String]) -> Vec<String> {
    labels
        .iter()
        .flat_map(|label| label.split(':'))
        .map(str::trim)
        .filter(|label| !label.is_empty())
        .map(str::to_string)
        .collect()
}

fn edge_type_from_str(raw: &str) -> GgEdgeType {
    match raw.to_ascii_uppercase().as_str() {
        "FORK" => GgEdgeType::Fork,
        "RACE" => GgEdgeType::Race,
        "FOLD" => GgEdgeType::Fold,
        "VENT" => GgEdgeType::Vent,
        "SLIVER" | "INTERFERE" => GgEdgeType::Interfere,
        _ => GgEdgeType::Process,
    }
}

fn first_edge_source(program: &GgProgram) -> Option<String> {
    program
        .edges
        .first()
        .and_then(|edge| edge.source_ids.first())
        .cloned()
}

fn gg_entry_function_name(program: &GgProgram) -> Option<String> {
    program.nodes.values().find_map(|node| {
        let has_entry = split_labels(&node.labels)
            .iter()
            .any(|label| label == "Entry" || label == "PolyglotBridgeEntry");
        if has_entry {
            node.properties.get("name").cloned()
        } else {
            None
        }
    })
}

fn implementation_file_path(file_path: &str, block: &gnot::GnarlyImplementationBlock) -> String {
    let extension = language_extension(&block.language).unwrap_or("txt");
    format!("{file_path}.{}.{}", block.node_id, extension)
}

fn language_extension(language: &str) -> Option<&'static str> {
    match language {
        "bash" => Some("sh"),
        "c" => Some("c"),
        "cpp" => Some("cpp"),
        "c_sharp" => Some("cs"),
        "elixir" => Some("exs"),
        "go" => Some("go"),
        "haskell" => Some("hs"),
        "java" => Some("java"),
        "javascript" => Some("js"),
        "kotlin" => Some("kt"),
        "lua" => Some("lua"),
        "ocaml" => Some("ml"),
        "php" => Some("php"),
        "python" => Some("py"),
        "ruby" => Some("rb"),
        "rust" => Some("rs"),
        "scala" => Some("scala"),
        "swift" => Some("swift"),
        "typescript" => Some("ts"),
        "zig" => Some("zig"),
        _ => None,
    }
}

fn file_stem(file_path: &str) -> String {
    Path::new(file_path)
        .file_stem()
        .and_then(|stem| stem.to_str())
        .filter(|stem| !stem.is_empty())
        .unwrap_or("main")
        .to_string()
}

#[cfg(test)]
mod tests {
    use super::*;

    const GNARLY: &str = r#"
gnarly "image-pipeline" {
  languages = ["typescript", "rust", "go"]
  entry = ingest
}

(ingest: PolyglotBridgeCall {
  language: "typescript",
  callee: "ingest"
})

(transform: PolyglotBridgeCall {
  fastest: true,
  candidates: ["rust", "go", "zig"],
  callee: "transform"
})

(ingest)-[:PROCESS]->(transform)

impl transform in typescript {
  export function transform() {
    return 42;
  }
}
"#;

    #[test]
    fn compiles_gnarly_to_orchestration_scan_result() {
        let result =
            parse_and_extract_gnarly_orchestration(GNARLY, "image.gnarly").expect("compile");

        assert_eq!(result.scan_result.language, "gnarly");
        assert!(result
            .scan_result
            .topologies
            .iter()
            .any(|topology| topology.function_name == "image-pipeline"));
        let main = &result.scan_result.topologies[0].topology;
        assert!(main
            .nodes
            .iter()
            .any(|node| node.id == "__gnarly_entry"
                && node.labels.iter().any(|label| label == "Entry")));
        let transform = main
            .nodes
            .iter()
            .find(|node| node.id == "transform")
            .expect("transform node");
        assert_eq!(
            transform.properties.get("candidates").map(String::as_str),
            Some(r#"["rust", "go", "zig"]"#)
        );
    }

    #[test]
    fn normalizes_gnarly_to_plain_gg() {
        let gg = normalize_gnarly_to_gg(GNARLY, "image.gnarly");

        assert!(gg.contains("(ingest: PolyglotBridgeCall"));
        assert!(!gg.contains("gnarly \"image-pipeline\""));
        assert!(!gg.contains("impl transform"));
    }
}
